const event = $input.item.json;
const isDeleted = event.status === 'cancelled';
let action = "";

const sourceNode = $input.params.triggerOn;

if (sourceNode === "eventCreated") {
  action = "create";
} else if (sourceNode === "eventUpdated") {
  action = "update";
} else if (sourceNode === "eventCancelled") {
  action = "soft_delete";
}

return {
  json: {
    // Action for routing
    action: action,

    // Google identifiers
    google_calendar_id: event.organizer?.email || 'primary', // Calendar ID
    google_event_id: event.id, // Specific event ID
    google_etag: event.etag,
    remote_modified_at: event.updated,

    // Event details
    title: event.summary || 'Untitled Event',
    description: event.description || null,
    location: event.location || null,
    event_datetime: event.start?.dateTime || event.start?.date,
    end_datetime: event.end?.dateTime || event.end?.date,
    all_day: !event.start?.dateTime,
    timezone: event.start?.timeZone || 'UTC',

    // Recurrence
    recurrence_rule: event.recurrence ? event.recurrence[0] : null,

    // Sync metadata
    sync_source: 'google',
    sync_status: 'synced',
    last_synced_at: new Date().toISOString(),
    local_modified_at: new Date().toISOString(),

    // Deletion tracking
    deleted: isDeleted,
    deleted_at: isDeleted ? new Date().toISOString() : null,
    deletion_synced_at: isDeleted ? new Date().toISOString() : null,

    // Defaults
    is_conflict: false,
    sync_attempts: 0,
    sync_error: null,

    // Your app fields
    type: 'other', // Default for Google-created events
    status: event.status,
    trip_id: null,
    whatsapp_group_id: null,
    user_id: null 
  }
};

